parameters.jsCode:
const emails = $input.all();
const results = [];

for (const email of emails) {
  results.push({
    json: {
      subject: email.json.subject || 'Kein Betreff',
      from: email.json.from || email.json.fromAddress || '',
      body: email.json.textAsHtml || email.json.text || '',
      date: email.json.date || new Date().toISOString(),
      messageId: email.json.messageId || '',
      category: 'unbekannt'
    }
  });
}

return results;

