parameters.jsCode:
const items = $input.all();
const results = [];

for (const item of items) {
  const response = JSON.parse(item.json.body || '{}');
  const category = (response.message?.content || 'sonstiges').trim().toLowerCase();
  results.push({
    json: {
      ...item.json,
      category: category
    }
  });
}

return results;

